class GithubUserProfile extends HTMLElement{static get observedAttributes(){return["username"]}constructor(){super(),this.attachShadow({mode:"open"}),this.username="bredfern"}connectedCallback(){this.render(),this.fetchData()}attributeChangedCallback(n,e,r){"username"===n&&e!==r&&(this.username=r,this.render(),this.fetchData())}async fetchData(){const n=this.shadowRoot.querySelector(".profile-container");n.innerHTML="<p>Loading profile and projects for <strong>"+this.username+"</strong>...</p>",n.classList.remove("error");try{const n=await fetch(`https://api.github.com/users/${this.username}`);if(!n.ok){if(404===n.status)throw new Error(`GitHub user "${this.username}" not found.`);throw new Error(`HTTP error! Status: ${n.status} fetching user data.`)}const e=await n.json(),r=await fetch(`https://api.github.com/users/${this.username}/repos?sort=updated&per_page=5`);if(!r.ok)throw new Error(`HTTP error! Status: ${r.status} fetching repository data.`);const o=await r.json();this.displayProfile(e,o)}catch(e){console.error("Error fetching GitHub data:",e),n.classList.add("error"),n.innerHTML=`<p><strong>Error:</strong> ${e.message}</p>`}}displayProfile(n,e){const r=this.shadowRoot.querySelector(".profile-container"),o=n=>n||"N/A",t=e.length>0?e.map(n=>`\n                <li class="repo-item">\n                    <a href="${n.html_url}" target="_blank" class="repo-name">${n.name}</a>\n                    <p class="repo-description">${o(n.description)}</p>\n                    <div class="repo-meta">\n                        <span>⭐ ${n.stargazers_count}</span>\n                        <span>🍴 ${n.forks_count}</span>\n                        <span class="language">${o(n.language)}</span>\n                    </div>\n                </li>\n            `).join(""):"<p>No public repositories found.</p>";r.innerHTML=`\n            <div class="profile-section">\n                <div class="profile-header">\n                    <img src="${n.avatar_url}" alt="${o(n.login)}'s avatar" class="avatar">\n                    <div>\n                        <h2>${o(n.name)}</h2>\n                        <p class="login-name">@${o(n.login)}</p>\n                    </div>\n                </div>\n                \n                <p class="bio">${o(n.bio)}</p>\n\n                <div class="stats">\n                    <div class="stat-item">\n                        <strong>Repos</strong>\n                        <span>${o(n.public_repos)}</span>\n                    </div>\n                    <div class="stat-item">\n                        <strong>Followers</strong>\n                        <span>${o(n.followers)}</span>\n                    </div>\n                    <div class="stat-item">\n                        <strong>Following</strong>\n                        <span>${o(n.following)}</span>\n                    </div>\n                </div>\n\n                <div class="details">\n                    <p><strong>Location:</strong> ${o(n.location)}</p>\n                    <p><strong>Company:</strong> ${o(n.company)}</p>\n                    <p><strong>Joined:</strong> ${new Date(n.created_at).toLocaleDateString()}</p>\n                </div>\n                <a href="${n.html_url}" target="_blank" class="github-link">View full profile on GitHub</a>\n            </div>\n\n            <h3 class="repos-heading">Public Projects (${e.length} / ${o(n.public_repos)})</h3>\n            <ul class="repos-list">\n                ${t}\n            </ul>\n        `}render(){this.shadowRoot.innerHTML='\n            <style>\n                :host {\n                    display: block;\n                    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif, "Apple Color Emoji", "Segoe UI Emoji", "Segoe UI Symbol";\n                    padding: 1.25rem;\n                    max-width: 40rem;\n                    margin: 1.25rem auto;\n                    margin-top: 0.7rem;\n                    box-shadow: 0 0.2rem  rgba(0, 0, 0, 0.05);\n                    background-color: #cececece;\n                    border-radius: 0.25rem;\n                    border: solid 0.1rem #cecece;\n                }\n                .profile-container {\n                    color: #000000;\n                }\n                .profile-container.error {\n                    color: #cb2431;\n                    border-left: 0.3rem solid #cb2431;\n                    padding-left: 1rem;\n                }\n                /* PROFILE STYLES (Kept from before) */\n                .profile-header { display: flex; align-items: center; margin-bottom: 0.5rem; }\n                .avatar { width: 4rem; height: 4rem; border-radius: 50%; margin-right: 0.5rem; border: 0.1rem solid #cecece }\n                h2 {\n                    margin: 0;\n                    font-size: 1.5em;\n                    color: #000000;\n                }\n                .login-name {\n                    margin: 0;\n                    color: #000000;\n                    font-size: 0.9em;\n                }\n                .bio { font-style: italic; margin: 10px 0; padding-bottom: 15px; border-bottom: 1px solid #cecece }\n                .stats {\n                    background-color: #fff;\n                    display: flex;\n                    justify-content: space-around;\n                    margin: 1rem 0;\n                    padding: 1rem 0;\n                }\n                .stat-item { \n                  text-align: center; \n                }\n                .stat-item strong { \n                  display: block; \n                  font-size: 1.1em; \n                  color: #00000; \n                }\n                .stat-item span { \n                  font-size: 0.8em; \n                }\n                .details p { \n                  margin: 0.25rem 0; \n                  font-size: 0.9em; \n                }\n                .github-link { \n                  display: block; \n                  text-align: center; \n                  margin-top: 0.5rem; \n                  padding: 0.25rem 0.5rem; \n                  background-color: #ffffff; \n                  color: #000000; \n                  text-decoration: none; \n                  border-radius: 0.25rem; \n                  font-weight: 500; \n                  font-size: 0.9em; \n                  transition: \n                  background-color 0.2s; \n                }\n                .github-link:hover { background-color: #cecece; }\n                /* REPOSITORY STYLES (New) */\n                .repos-heading {\n                    font-size: 1.2em;\n                    margin-top: 0.5rem;\n                    padding-top: 0.25rem;\n                    border-top: 0.1rem solid #cecece;\n                    color: #000;\n                }\n                .repos-list {\n                    list-style: none;\n                    padding: 0;\n                    margin: 0;\n                }\n                .repo-item {\n                    border: 0.1rem solid #e0e2ddff\n                    border-radius: 0.25rem;\n                    padding: 0.25rem;\n                    color: #000000;\n                    margin-bottom: 0.25rem;\n                    background-color: #ffffff;\n                    transition: box-shadow 0.2s;\n                }\n                .repo-item:hover {\n                    box-shadow: 0 0.1rem 0.5rem rgba(0, 0, 0, 0.1);\n                }\n                .repo-name {\n                    font-weight: 600;\n                    color: #000000;\n                    text-decoration: none;\n                    font-size: 1.1em;\n                }\n                .repo-description {\n                    font-size: 0.9em;\n                    color: #000000;\n                    margin: 0.25rem 0;\n                }\n                .repo-meta {\n                    display: flex;\n                    gap: 0.25rem;\n                    font-size: 0.8em;\n                    color: #000000;\n                    margin-top: 0.25rem;\n                }\n                .repo-meta span {\n                    display: flex;\n                    align-items: center;\n                }\n                .repo-meta .language {\n                    font-weight: 500;\n                    color: #000000;\n                }\n            </style>\n            <div class="profile-container">\n            </div>\n        '}}customElements.define("github-user-profile",GithubUserProfile);